# solution.py
"""Team_Collaboration_Manager.

A thread-safe, in-memory team collaboration backend that manages users,
projects, tasks, messaging (with attachments and threaded replies), individual
and team performance analytics, peer ratings, and exportable reports
(CSV / PDF).

The module is implemented with the standard library only and is ASCII clean.

Design notes
------------
* All entity identifiers are drawn from a single, process-wide monotonically
  increasing counter, so ids are unique across every entity type and start at 1.
* A single re-entrant lock is shared by the manager and every sub-store, which
  makes the public API safe to call from many threads at once.
* Every getter returns a deep copy of the stored entity (or a fresh list of
  deep copies), so callers can never mutate the internal state by accident.
"""

from __future__ import annotations

import copy
import csv
import io
import json
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Roles a user may hold inside the workspace."""

    MEMBER = "member"
    ADMIN = "admin"
    OWNER = "owner"
    GUEST = "guest"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the collaboration manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input data is malformed or violates a business rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not allowed to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing related state."""


# ---------------------------------------------------------------------------
# Domain models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A binary attachment associated with a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime
    content_type: str = "application/octet-stream"


@dataclass
class User:
    """A workspace member."""

    id: int
    username: str
    email: str
    role: UserRole = UserRole.MEMBER
    created_at: Optional[datetime] = None


@dataclass
class Project:
    """A time-boxed container that owns tasks and messages."""

    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""
    created_at: Optional[datetime] = None


@dataclass
class Task:
    """A unit of work that can be assigned, scheduled and tracked."""

    id: int
    project_id: int
    title: str
    assignee_id: Optional[int] = None
    status: TaskStatus = TaskStatus.NOT_STARTED
    deadline: Optional[datetime] = None
    description: str = ""
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Message:
    """A message posted to either a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating given by one user to another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Internal stores
#
# Each store only holds data plus a reference to the *shared* lock.  All
# orchestration and validation lives on the manager.  Keeping the lock object
# identical across stores is part of the public contract (it guarantees that a
# single critical section protects the whole object graph).
# ---------------------------------------------------------------------------
class _BaseStore:
    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock


class _UserStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._items: Dict[int, User] = {}
        self._by_username: Dict[str, int] = {}
        self._by_email: Dict[str, int] = {}


class _ProjectStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._items: Dict[int, Project] = {}


class _TaskStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._items: Dict[int, Task] = {}
        self._by_project: Dict[int, set] = {}
        self._by_assignee: Dict[int, set] = {}


class _MessageStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._items: Dict[int, Message] = {}
        self._by_project: Dict[int, List[int]] = {}
        self._by_task: Dict[int, List[int]] = {}


class _PerformanceStore(_BaseStore):
    def __init__(self, lock: "threading.RLock") -> None:
        super().__init__(lock)
        self._ratings: Dict[int, Rating] = {}
        self._by_ratee: Dict[int, List[int]] = {}


class _ReportStore(_BaseStore):
    """Reports are computed on demand; this store only carries the lock."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Facade that exposes the full collaboration API.

    Parameters
    ----------
    now:
        Optional zero-argument callable returning the "current" ``datetime``.
        Injecting a clock makes time-dependent behaviour deterministic in
        tests.  Defaults to :func:`datetime.datetime.now`.
    """

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now: Callable[[], datetime] = now if now is not None else datetime.now
        self._id_counter = 0

        # Sub-stores share the single lock instance.
        self.users = _UserStore(self._lock)
        self.projects = _ProjectStore(self._lock)
        self.tasks = _TaskStore(self._lock)
        self.messages = _MessageStore(self._lock)
        self.performance = _PerformanceStore(self._lock)
        self.reports = _ReportStore(self._lock)

    # -- infrastructure helpers --------------------------------------------
    def _next_id(self) -> int:
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    @staticmethod
    def _clone(obj):
        return copy.deepcopy(obj)

    def _require_user(self, user_id: int) -> User:
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id: int) -> Project:
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id: int) -> Task:
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id: int) -> Message:
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    @staticmethod
    def _validate_non_empty(value: str, label: str) -> str:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value

    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str) or not email.strip():
            raise ValidationError("email must be a non-empty string")
        if "@" not in email:
            raise ValidationError("email must contain '@'")
        return email

    # ------------------------------------------------------------------ #
    # User management
    # ------------------------------------------------------------------ #
    def register_user(
        self,
        username: str,
        email: str,
        role: UserRole = UserRole.MEMBER,
    ) -> User:
        """Create and store a new user."""
        self._validate_non_empty(username, "username")
        self._validate_email(email)
        if not isinstance(role, UserRole):
            raise ValidationError("role must be a UserRole")

        with self._lock:
            if username in self.users._by_username:
                raise DuplicateError("username already in use")
            if email in self.users._by_email:
                raise DuplicateError("email already in use")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            self.users._by_username[username] = user.id
            self.users._by_email[email] = user.id
            return self._clone(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            return [self._clone(self.users._items[i]) for i in sorted(self.users._items)]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._require_user(user_id)

            if username is not None:
                self._validate_non_empty(username, "username")
                owner = self.users._by_username.get(username)
                if owner is not None and owner != user_id:
                    raise DuplicateError("username already in use")

            if email is not None:
                self._validate_email(email)
                owner = self.users._by_email.get(email)
                if owner is not None and owner != user_id:
                    raise DuplicateError("email already in use")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None and username != user.username:
                del self.users._by_username[user.username]
                user.username = username
                self.users._by_username[username] = user_id

            if email is not None and email != user.email:
                del self.users._by_email[user.email]
                user.email = email
                self.users._by_email[email] = user_id

            if role is not None:
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            user = self._require_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns one or more projects")

            assigned = self.tasks._by_assignee.get(user_id, set())
            for task_id in assigned:
                task = self.tasks._items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open assigned tasks")

            # Detach the user from any completed tasks that remain.
            for task_id in list(assigned):
                task = self.tasks._items.get(task_id)
                if task is not None:
                    task.assignee_id = None
            self.tasks._by_assignee.pop(user_id, None)

            del self.users._items[user_id]
            self.users._by_username.pop(user.username, None)
            self.users._by_email.pop(user.email, None)

    # ------------------------------------------------------------------ #
    # Project management
    # ------------------------------------------------------------------ #
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            self._require_user(owner_id)
            self._validate_non_empty(name, "project name")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            project = Project(
                id=self._next_id(),
                name=name,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description,
                created_at=self._now(),
            )
            self.projects._items[project.id] = project
            return self._clone(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            return [
                self._clone(self.projects._items[i])
                for i in sorted(self.projects._items)
            ]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
        owner_id: Optional[int] = None,
    ) -> Project:
        with self._lock:
            project = self._require_project(project_id)

            if name is not None:
                self._validate_non_empty(name, "project name")
            if owner_id is not None:
                self._require_user(owner_id)

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = name
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            if owner_id is not None:
                project.owner_id = owner_id

            return self._clone(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._require_project(project_id)

            # Cascade tasks (and their messages).
            for task_id in list(self.tasks._by_project.get(project_id, set())):
                task = self.tasks._items.pop(task_id, None)
                if task is not None and task.assignee_id is not None:
                    bucket = self.tasks._by_assignee.get(task.assignee_id)
                    if bucket is not None:
                        bucket.discard(task_id)
                for message_id in list(self.messages._by_task.get(task_id, [])):
                    self.messages._items.pop(message_id, None)
                self.messages._by_task.pop(task_id, None)
            self.tasks._by_project.pop(project_id, None)

            # Cascade project-level messages.
            for message_id in list(self.messages._by_project.get(project_id, [])):
                self.messages._items.pop(message_id, None)
            self.messages._by_project.pop(project_id, None)

            del self.projects._items[project_id]

    # ------------------------------------------------------------------ #
    # Task management
    # ------------------------------------------------------------------ #
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
        description: str = "",
    ) -> Task:
        with self._lock:
            project = self._require_project(project_id)
            self._validate_non_empty(title, "task title")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title,
                assignee_id=assignee_id,
                deadline=deadline,
                description=description,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            self.tasks._by_project.setdefault(project_id, set()).add(task.id)
            if assignee_id is not None:
                self.tasks._by_assignee.setdefault(assignee_id, set()).add(task.id)
            return self._clone(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.tasks._by_project.get(project_id, set()))
            return [self._clone(self.tasks._items[i]) for i in ids]

    def list_tasks_by_assignee(self, user_id: int) -> List[Task]:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self.tasks._by_assignee.get(user_id, set()))
            return [self._clone(self.tasks._items[i]) for i in ids]

    def _set_assignee(self, task: Task, new_assignee_id: Optional[int]) -> None:
        old = task.assignee_id
        if old == new_assignee_id:
            return
        if old is not None:
            bucket = self.tasks._by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_assignee_id
        if new_assignee_id is not None:
            self.tasks._by_assignee.setdefault(new_assignee_id, set()).add(task.id)

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            self._set_assignee(task, assignee_id)
            return self._clone(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return self._clone(task)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            self._set_assignee(task, None)
            return self._clone(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._require_task(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            else:  # NOT_STARTED
                task.started_at = None
                task.completed_at = None

            task.status = status
            return self._clone(task)

    # ------------------------------------------------------------------ #
    # Messaging
    # ------------------------------------------------------------------ #
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[List[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._require_user(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self._require_project(project_id)
            if task_id is not None:
                self._require_task(task_id)
            if parent_id is not None:
                self._require_message(parent_id)

            attachment_specs = attachments or []
            has_body = bool(body and body.strip())
            if not has_body and not attachment_specs:
                raise ValidationError("message must have a body or attachments")

            now = self._now()
            attachment_objs = [
                self._build_attachment(filename, data, author_id, now)
                for filename, data in attachment_specs
            ]

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
            )
            self.messages._items[message.id] = message
            if project_id is not None:
                self.messages._by_project.setdefault(project_id, []).append(message.id)
            if task_id is not None:
                self.messages._by_task.setdefault(task_id, []).append(message.id)
            return self._clone(message)

    def _build_attachment(
        self, filename: str, data: bytes, uploaded_by: int, when: datetime
    ) -> Attachment:
        if not isinstance(filename, str) or not filename.strip():
            raise ValidationError("attachment filename must be a non-empty string")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=when,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            has_body = bool(new_body and new_body.strip())
            if not has_body and not message.attachments:
                raise ValidationError("message must have a body or attachments")
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach files to this message"
                )
            attachment = self._build_attachment(
                filename, data, uploader_id, self._now()
            )
            message.attachments.append(attachment)
            return self._clone(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._require_project(project_id)
            ids = sorted(self.messages._by_project.get(project_id, []))
            return [self._clone(self.messages._items[i]) for i in ids]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._require_task(task_id)
            ids = sorted(self.messages._by_task.get(task_id, []))
            return [self._clone(self.messages._items[i]) for i in ids]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            if message.project_id is not None:
                bucket = self.messages._by_project.get(message.project_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            if message.task_id is not None:
                bucket = self.messages._by_task.get(message.task_id)
                if bucket is not None and message_id in bucket:
                    bucket.remove(message_id)
            del self.messages._items[message_id]

    # ------------------------------------------------------------------ #
    # Performance dashboard
    # ------------------------------------------------------------------ #
    def _tasks_for_assignee(self, user_id: int) -> List[Task]:
        ids = self.tasks._by_assignee.get(user_id, set())
        return [self.tasks._items[i] for i in ids if i in self.tasks._items]

    @staticmethod
    def _completion_seconds(task: Task) -> Optional[float]:
        if (
            task.status == TaskStatus.COMPLETED
            and task.started_at is not None
            and task.completed_at is not None
        ):
            return (task.completed_at - task.started_at).total_seconds()
        return None

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._require_user(user_id)
            durations = [
                self._completion_seconds(t)
                for t in self._tasks_for_assignee(user_id)
            ]
            durations = [d for d in durations if d is not None]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if rater_id == ratee_id:
                raise ConflictError("users may not rate themselves")

            self._require_user(rater_id)
            self._require_user(ratee_id)
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._ratings[rating.id] = rating
            self.performance._by_ratee.setdefault(ratee_id, []).append(rating.id)
            return self._clone(rating)

    def _ratings_for(self, user_id: int) -> List[Rating]:
        ids = self.performance._by_ratee.get(user_id, [])
        return [self.performance._ratings[i] for i in ids if i in self.performance._ratings]

    def get_ratings_summary(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ratings = self._ratings_for(user_id)
            count = len(ratings)
            average = (sum(r.score for r in ratings) / count) if count else 0.0
            return {
                "user_id": user_id,
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_assignee(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            durations = [self._completion_seconds(t) for t in tasks]
            durations = [d for d in durations if d is not None]
            average_completion_time = (
                sum(durations) / len(durations) if durations else None
            )

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": average_completion_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------ #
    # Reports
    # ------------------------------------------------------------------ #
    def _avg_completion_for_tasks(self, tasks: List[Task]) -> Optional[float]:
        durations = [self._completion_seconds(t) for t in tasks]
        durations = [d for d in durations if d is not None]
        if not durations:
            return None
        return sum(durations) / len(durations)

    def project_progress_report(self, project_id: int) -> dict:
        with self._lock:
            self._require_project(project_id)
            ids = self.tasks._by_project.get(project_id, set())
            tasks = [self.tasks._items[i] for i in ids]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                row = per_assignee.setdefault(
                    task.assignee_id,
                    {"total_tasks": 0, "completed_tasks": 0},
                )
                row["total_tasks"] += 1
                if task.status == TaskStatus.COMPLETED:
                    row["completed_tasks"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": (completed / total) if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id: Optional[int] = None) -> dict:
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)
                ids = self.tasks._by_project.get(project_id, set())
                tasks = [self.tasks._items[i] for i in ids]
            else:
                tasks = list(self.tasks._items.values())

            by_assignee: Dict[int, List[Task]] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                by_assignee.setdefault(task.assignee_id, []).append(task)

            rows = []
            for uid in sorted(by_assignee):
                user_tasks = by_assignee[uid]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                )
                user = self.users._items.get(uid)
                ratings = self._ratings_for(uid)
                rating_average = (
                    sum(r.score for r in ratings) / len(ratings) if ratings else 0.0
                )
                rows.append(
                    {
                        "user_id": uid,
                        "username": user.username if user is not None else None,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": (completed / total) if total else 0.0,
                        "average_completion_time": self._avg_completion_for_tasks(
                            user_tasks
                        ),
                        "rating_average": rating_average,
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> dict:
        with self._lock:
            self._require_user(user_id)
            ids = sorted(self.tasks._by_assignee.get(user_id, set()))
            tasks = [self.tasks._items[i] for i in ids]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)

            ratings = self._ratings_for(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            task_rows = [
                {
                    "task_id": t.id,
                    "project_id": t.project_id,
                    "title": t.title,
                    "status": t.status.value,
                    "assignee_id": t.assignee_id,
                    "deadline": t.deadline,
                    "started_at": t.started_at,
                    "completed_at": t.completed_at,
                }
                for t in tasks
            ]

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": (completed / total) if total else 0.0,
                "average_completion_time": self._avg_completion_for_tasks(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    # ------------------------------------------------------------------ #
    # Export
    # ------------------------------------------------------------------ #
    def export_report(self, report: dict, fmt: ReportFormat):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict produced by a report method")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")

        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        if fmt == ReportFormat.PDF:
            return self._report_to_pdf(report)
        raise ValidationError("unsupported report format")

    @staticmethod
    def _cell(value) -> str:
        if value is None:
            return ""
        if isinstance(value, (dict, list)):
            return json.dumps(value, default=str, sort_keys=True)
        if isinstance(value, datetime):
            return value.isoformat()
        return str(value)

    def _report_to_csv(self, report: dict) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([self._cell(row.get(col)) for col in header])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id",
                "project_id",
                "title",
                "status",
                "assignee_id",
                "deadline",
                "started_at",
                "completed_at",
            ]
            writer.writerow(header)
            for row in report.get("tasks", []):
                writer.writerow([self._cell(row.get(col)) for col in header])

        else:
            writer.writerow(["field", "value"])
            for key, value in report.items():
                writer.writerow([self._cell(key), self._cell(value)])

        return buffer.getvalue()

    def _report_to_pdf(self, report: dict) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            lines.append("{0}: {1}".format(key, self._cell(value)))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines: List[str]) -> bytes:
        """Assemble a minimal, structurally valid single-page PDF document."""

        def escape(text: str) -> str:
            return (
                text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 11 Tf", "50 760 Td", "14 TL"]
        for line in lines:
            safe = escape(line).encode("ascii", "replace").decode("ascii")
            content_parts.append("({0}) Tj".format(safe))
            content_parts.append("T*")
        content_parts.append("ET")
        content = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>",
            b"<< /Length "
            + str(len(content)).encode("latin-1")
            + b" >>\nstream\n"
            + content
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += "{0} 0 obj\n".format(index).encode("latin-1")
            pdf += body
            pdf += b"\nendobj\n"

        xref_position = len(pdf)
        count = len(objects) + 1
        pdf += "xref\n0 {0}\n".format(count).encode("latin-1")
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
        pdf += (
            "trailer\n<< /Size {0} /Root 1 0 R >>\nstartxref\n{1}\n%%EOF\n".format(
                count, xref_position
            ).encode("latin-1")
        )
        return bytes(pdf)


